var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식파를 동반한 모래 폭풍이 소멸하였음을 알려드립니다. </color>","JPN":"<color=#ffd34c>侵食波を伴う、砂嵐が消滅したことをお知らせいたします。</color>","ENG":"<color=#ffd34c>The sandstorm accompanied by the Corruption rays has been dissipated.</color>","TWN":"<color=#ffd34c>通知，挾帶侵蝕波的沙塵暴已消失。</color>"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>금일, 기상 조절기는 폭풍 없이 맑은 날씨를 유지할 예정입니다. </color>","JPN":"<color=#ffd34c>本日、気象調節器は嵐も起こることなく、ずっと晴れを維持する予定です。</color>","ENG":"<color=#ffd34c>The weather controller expects clear skies without any sandstorm for today.</color>","TWN":"<color=#ffd34c>今日，氣候調節器預計將保持晴朗天氣，沒有風暴。</color>"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>다시 한번 알려드립니다……. </color>","JPN":"<color=#ffd34c>繰り返します……</color>","ENG":"<color=#ffd34c>Once again...</color>","TWN":"<color=#ffd34c>重複一遍……</color>"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아직 못 찾았나요?","JPN":"まだ見つかっていないのですか？","ENG":"Haven't you found them yet?","TWN":"還沒找到人嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"워낙에 신출귀몰해서 수색이 어렵습니다.","JPN":"神出鬼没すぎて、捜索に手こずっています。","ENG":"They are like ghosts, so it's difficult to find them.","TWN":"那幾個人神出鬼沒的，很難找。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"발견했다 싶으면 좌표를 왜곡해서 달아나니…… 쉽지 않군요.","JPN":"見つけたと思ったら座標を歪ませて逃げますし……手ごわいですね。","ENG":"Even if I do find them, they distort the coordinates and flee... This will take some time.","TWN":"就算發現到，她們也會扭曲座標逃跑……不太容易。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"하아…… 위에선 토벌한 침식체와 관련된 인물에 대한 정보를 요구하고 있어요.","JPN":"はあ……上層部からは討伐した侵食体と関係のある人物の情報を要求しています。","ENG":"*Sigh* The higher-ups are asking for information about the people related to the extermination of the C.O.","TWN":"哀哀……上面要求提供討伐侵蝕體相關人物的資料。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"잔해 회수엔 시간이 걸리고, 토벌한 카운터에 대한 정보라도 얻으려는 것 같은데…….","JPN":"残骸の回収には時間がかかり、討伐したカウンターの情報でも手に入れようとしているようですが……","ENG":"Since collecting the C.O.'s remains will take time, I think they're trying to obtain information on the Counter that killed it, but...","TWN":"回收侵蝕體殘骸需要時間，似乎是想透過討伐者獲取情報……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아무튼, 최대한 협조를 구해보도록 해요.","JPN":"とにかく、関係者の皆さんに協力をお願いしてみましょう。","ENG":"Anyway, let's try to get as much cooperation as possible.","TWN":"不管怎樣，讓我們盡可能與他們合作。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"죄송하지만, 조금 더 고생해주세요.","JPN":"こんなこと言うのも悪いですが、もう少し頑張ってくださいね。","ENG":"I'm sorry to ask, but please try a little harder.","TWN":"對不起，請再多辛苦一下。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……갔어요.","JPN":"……行きました。","ENG":"...They're gone.","TWN":"……走咧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"휘유! 들키는 줄 알았네!","JPN":"ふう！　バレるかと思った！","ENG":"Phew! I thought we were going to get caught!","TWN":"呼！幸好沒被發現！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"전대장님! 구태여 여기 숨어있을 필요가 있나요?","JPN":"戦隊長！　ここに隠れている必要ありますか？","ENG":"Commander! Do we really need to keep hiding from them?","TWN":"戰隊長！真的有必要藏在這裡嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"맞아요. 그냥 <color=#ffd34c>내가 구 관리국의 전대장이다! </color> 라고 한마디만 하시면…….","JPN":"そうですよ。別に<color=#ffd34c>私が旧管理局の戦隊長だ！</color>って一言言えば……","ENG":"She's right. If you just say, <color=#ffd34c>\\"I am a former Commander of the Old Administration!\\"</color>","TWN":"沒錯。只要你說一句，<color=#ffd34c>我是舊管理局的戰隊長！</color>……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"지금 정체를 드러낼 생각은 없다.","JPN":"今正体を現すつもりはない。","ENG":"I have no intention of revealing my identity at this moment.","TWN":"現在還不是暴露身份的時候。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그저 오래전 끝내야 했던 임무를 마친 것뿐이니까.","JPN":"かつて果たせなかった任務を、やっと終わらせただけだからな。","ENG":"All I have done is merely complete a mission long overdue.","TWN":"我只是完成很久以前就該完成的任務而已。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"게다가 나는 아직 지금의 관리국에 대한 정보가 부족해.","JPN":"それに、私はまだ今の管理局の情報が足りない。","ENG":"Also, I lack information on the current Administration.","TWN":"而且對現在的管理局還缺乏足夠的資訊。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하긴……지금의 관리국은 구 관리국과 태도가 다를 수도 있겠어요.","JPN":"確かに……今の管理局は旧管理局とは違う態度を取られるかもしれません。","ENG":"I guess you're right... The current Administration might have a different attitude from the Old Administration.","TWN":"確實……現在的管理局可能和舊管理局的態度不同。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"급한 것도 아니니까! 천천히 생각하도록 하죠!","JPN":"急用でもないですし！　ゆっくり考えましょう！","ENG":"And we're in no hurry! So, let's take our time and think about it!","TWN":"也不急！那就慢慢想吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그나저나 전대장님. 동결되어 있었다는 건 무슨 얘기죠?","JPN":"それより戦隊長。凍結されていたというのはどういうことですか？","ENG":"Anyway, Commander. Why were you in cryogenic sleep?","TWN":"話說回來，戰隊長，膠囊又是怎麼回事？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"작전이 실패한 후, 도착한 카멜롯은 정신을 잃은 나를 구출했다.","JPN":"作戦が失敗した後、到着したキャメロットは気を失っていた私を救出した。","ENG":"After the operation failed, Camelot arrived and rescued me while I was unconscious.","TWN":"作戰失敗後，趕到的卡梅羅救出昏迷的我。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 테라브레인으로부터 작전 수행 불가 판정을 받았지.","JPN":"だが、テラブレインから作戦遂行不可と判定されてな。","ENG":"But Terrabrain deemed that the operation was impossible to be carried out.","TWN":"但是特拉大腦判斷我無法繼續執行作戰。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"말소된 정보는 복구한 모양이지만, 내 부상은 당장 해결할 수 없는 수준이었어.","JPN":"抹消された情報は何とか復元できたようだが、私の怪我はすぐに治せるレベルではなかった。","ENG":"I think they've restored the erased information, but my injuries were at a level that couldn't be treated immediately.","TWN":"雖然似乎已經復原被抹除的記錄，但我的傷勢當下無法立刻處理好。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"결국 테라브레인은 내가 회복될 때까지 동결하기로 결정했다.","JPN":"結局テラブレインは私が回復するまで凍結させると決めた。","ENG":"Ultimately, Terrabrain decided to put me into cryogenic sleep until I fully recovered.","TWN":"最後，特拉大腦就決定在我恢復之前把我冰封起來。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"물론, 나를 깨워야 했던 관리국이 먼저 무너져 내릴 줄은 몰랐지만.","JPN":"もちろん、私を起こすべき管理局が先に崩壊するとは思っていなかったのだろうがな。","ENG":"Of course, no one knew that the Administration that was supposed to wake me up would collapse first.","TWN":"只是沒想到在叫醒我之前管理局會先瓦解。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"하지만 동결 조치는…….","JPN":"ですが、凍結措置は……","ENG":"But them putting you in a cryogenic stasis means...","TWN":"但是冰封措施……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"전대원을 모두 잃었다고 하더라도, 나는 전대장이다.","JPN":"たとえ戦隊員を皆失くしても、私は戦隊長だ。","ENG":"Even though I had lost all my division members, I was still a Commander.","TWN":"即使失去所有隊員，我依然是戰隊長。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"카운터 한 명 한 명이 아까웠던 그때라면 충분히 납득할 수 있는 상황이었어.","JPN":"カウンター不足だったあの頃なら、十分納得できる状況だったのだ。","ENG":"What they did was understandable given that Counters were rare at the time.","TWN":"如果是當時每一個制裁者都很寶貴的情況，那是完全可以理解的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"사전에 동의했던 사항이니 그렇게 불만 가득한 표정 지을 것 없다.","JPN":"事前に同意していたものだから、そう不満そうな顔をしなくてもいい。","ENG":"It had been agreed upon in advance, so there's no need to look so discontent.","TWN":"事先已經同意的事項，不要擺出一副不滿的表情。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아닐라, 우리는 모두 선택을 해야 해.\xA0","JPN":"アニラ、私たちは選択しなければならない。\xA0","ENG":"Anila, we all must make our own choices.\xA0","TWN":"雅妮拉，我們都必須做出選擇。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"너는 예전부터 결과가 마음에 들지 않으면 그런 얼굴을 하곤 했지.","JPN":"君は昔から結果が気に入らないとそんな顔をしていたな。","ENG":"You always made that face whenever you fought the results unfavorable to you.","TWN":"你從以前開始，只要對結果不滿意，就會露出那樣的表情。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"결국 그날의 선택이 이런 결과라도 낼 수 있었던 거야.","JPN":"結局、あの日の選択があったから、なんとか今の結果に辿り着けたのだぞ。","ENG":"In the end, the choices made that day are what led to these results.","TWN":"但最後，是那天的選擇才導致這樣的結果。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"너희가 날 도시 밖으로 빼내고, 기절시키고, 동결시켜서…….","JPN":"君たちが私を都市の外に引っ張り出し、気絶させ、凍結させ……","ENG":"You got me out of the city, knocked me unconscious, and put in me cryogenic sleep...","TWN":"你們把我從城市裡送出來，弄暈我，然後冰封我……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"……하아. 알겠어요. 결국 일은 해결됐으니까.","JPN":"……はあ。わかりました。もう解決したのですから。","ENG":"...*Sigh* Okay. Anyway, the mission was complete in the end.","TWN":"……哈哈。好啦，反正事情解決就好。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"<color=#ffd34c> 나아가야죠. 전대가 그러했던 것처럼. </color>","JPN":"<color=#ffd34c>前に進まないといけませんね。戦隊がそうだったように。</color>","ENG":"<color=#ffd34c>We must go forth. Just like the division did.</color>","TWN":"<color=#ffd34c> 我們必須前進，就像之前戰隊一樣。 </color>"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래…… 이해해줘서 고맙다.","JPN":"そうか……理解してくれてありがとう。","ENG":"Yes... Thank you for understanding.","TWN":"嗯……謝謝你的體諒。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그나저나 세상이 이렇게 바뀔 줄은 몰랐네요. 내가 너무 늙었나 싶기도 하고…….","JPN":"それより、世界がこんなに変わっているとは思ってもいませんでした。私が年を取りすぎたのかもしれません……","ENG":"Anyway, who knew the world would change so much like this? Or am I just getting old...?","TWN":"話說回來，沒想到世界會變成這樣。感覺我好老……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"특히 놀랐던 건 그거였어.","JPN":"特に驚いたのがまさにそれだ。","ENG":"What I was most surprised about was this.","TWN":"特別讓我驚訝的是那個。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"카운터로 이루어진 외인부대. 과거의 내가 이 얘길 들었다면 분명 헛소리로 치부했을 거다.","JPN":"カウンターで構成された外人部隊。過去の私がこの話を聞いたら、きっと戯言扱いしただろう。","ENG":"A foreign legion made up of Counters. If you told me about them in the past, I would've scoffed and dismissed it as nonsense.","TWN":"由制裁者組成的外部部隊。如果過去的我聽到這個消息，一定會認為是胡說八道。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"외인 부대가 아니라 태스크포스요.","JPN":"外人部隊じゃなくて、タスクフォースです。","ENG":"It's not called a foreign legion. It's called a TASKFORCE.","TWN":"不是外部部隊，是叫特遣勢力喔。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"몰라, 그런거…….","JPN":"知るか、そんなもの……","ENG":"Sounds like the same thing to me...","TWN":"我才沒聽過那種東西……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 전대장님이나 저나 바뀐 세상에 적응하려면 시간이 좀 걸리겠어요.","JPN":"あはは。戦隊長も私も、変わった世界に適応するためには時間が掛かりそうですね。","ENG":"Ah hah hah. I guess it'll take some time for you and me to adapt to the changed world, Commander.","TWN":"呵呵呵，無論是前隊長還是我，都需要一些時間來適應這個世界的變化。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그나저나 큰일이네요.","JPN":"それより、大変です。","ENG":"There's another problem we need to deal with.","TWN":"糟糕。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"오랜만에 세상에 나와보니 직장은 사라지고, 신원도 말소된 셈이잖아요?","JPN":"久々に外に出てみたら、職場は消えて身元も抹消されてたんですよ。","ENG":"Coming back out to the world after such a long time, we've lost our jobs and our identities have been erased.","TWN":"好不容易重回現世，結果工作沒了，身份也被註銷了？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"요즘은 어떤 일을 해야 먹고 살 수 있으려나…….","JPN":"この時代ではどんな仕事をして生きていけばいいのやら……","ENG":"I wonder if there is any work we can do...","TWN":"該做什麼活才能養活自己呢……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우선, 세상 돌아가는 것부터 배우자고요.","JPN":"まずは、世の中の常識から勉強しましょう。","ENG":"First, let's see how the changed world works.","TWN":"首先，學會如何適應這個世界吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"자, 여기 신문이에요. 신문 보는 법은 아시죠?","JPN":"はい、新聞です。新聞の読み方はわかっていますよね？","ENG":"Here. It's a newspaper. You do know how to read one, right?","TWN":"來，這是報紙。你知道怎麼看報紙吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"완전 뒷방 늙은이 취급을 받고 있잖아…….","JPN":"完全に老いぼれ扱いされているな……","ENG":"You're treating me like I'm ancient...","TWN":"現在是以為我是活化石嗎……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"배려해주는 건 좋지만, 나 때도 스마트폰으로 뉴스 정도는 볼 수 있었어…….","JPN":"心遣いはありがたいが、私の時代でもスマートフォンでニュースくらいは見られたぞ……","ENG":"I appreciate your consideration, but I also read news from a smartphone even then–","TWN":"謝謝你喔，但我以前也是會用智慧手機看新聞的……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저도 길거리에 나돌아다니는 걸 주워다 드린 거라고요!","JPN":"私も道に落ちてたものを拾っただけです！","ENG":"I just picked up one tossed on the streets and gave it to you!","TWN":"我在街上只能撿到這個嘛！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"신원도 불분명한 사람이 이것저것 따질 때예요?!","JPN":"身元も不明な人があれこれ気にしている場合ですか！？","ENG":"We don't have the luxury of being picky when we have no way of identifying ourselves, you know!","TWN":"現在是你們兩個挑三揀四的時候嗎！？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"흠흠…… 뭐 말이 그렇다는 거였다. 어디 보자…….","JPN":"コホン……別に事実を言ったまでだ。どれどれ……","ENG":"Ahem... I'm just saying, that's all. Let's see here...","TWN":"咳咳……只是說說而已。我看看……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"응? 이 자는……?","JPN":"ん？　この者は……？","ENG":"Hmm? Who is this...?","TWN":"嗯？這個人是……？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};